import React from "react";
import { useLocation, useParams } from "react-router-dom";

const TourDetail = () => {
  const location = useLocation();
  const { tourId } = useParams();

  const tour = location.state?.tour;

  if (!tour) {
    return (
      <p>
        Không tìm thấy thông tin chi tiết của tour (hãy truy cập từ danh sách).
      </p>
    );
  }

  return (
    <div>
      <h1>{tour.title}</h1>
      <img src={tour.images[0]} alt={tour.title} style={{ maxWidth: "100%" }} />
      <p>
        <strong>Thời gian:</strong> {tour.time}
      </p>
      <p>
        <strong>Số lượng:</strong> {tour.quantity} người
      </p>
      <p>
        <strong>Giá người lớn:</strong>{" "}
        {tour.priceAdult.toLocaleString("vi-VN")} VND
      </p>
      <p>
        <strong>Mô tả:</strong> {tour.description || "Chưa có mô tả"}
      </p>
    </div>
  );
};

export default TourDetail;
